"},{"node":"extractContainerIDFromProc","qualified_name":"Users-ilyabrykau-src-orca-runtime-sensor.pkg.containermonitor.monitor_unix.extractContainerIDFromProc","label":"Function","file":"pkg/containermonitor/monitor_unix.go","start_line":142,"end_line":158,"in_degree":1,"out_degree":1,"match_lines":[142],"source":"func extractContainerIDFromProc(procfsDir string, pid uint32) (string, error) {
	content, err := os.ReadFile(filepath.Join(procfsDir, strconv.Itoa(int(pid)), "cgroup"))
	if err != nil {
		return "", fmt.Errorf("failed to read cgroup file for pid %d: %w", pid, err)
	}
	for _, line := range strings.Split(strings.TrimSpace(string(content)), "\n") {
		fields := strings.SplitN(line, ":", 3)
		if len(fields) != 3 {
			continue
		}
		containerID, err := procutils.ExtractContainerIDFromCgroupPath(fields[2])
		if err == nil {
			return containerID, nil
		}
	}
	return "", fmt.Errorf("no container ID found in cgroup file for pid %d", pid)
}
