		require.NoError(t, os.MkdirAll(procDir, 0o777))

		statusContent := fmt.Sprintf("Name:\ttest\nPid:\t%d\nPPid:\t1\nUid:\t0\t0\t0\t0\nGid:\t0\t0\t0\t0\nNStgid:\t%d\t1\nNSpid:\t%d\t1\nNSpgid:\t0\t0\nNSsid:\t0\t0\n", pid, pid, pid)
		require.NoError(t, os.WriteFile(filepath.Join(procDir, "status"), []byte(statusContent), 0o644))
		require.NoError(t, os.WriteFile(filepath.Join(procDir, "uid_map"), []byte("      0       0 4294967295\n"), 0o644))
		require.NoError(t, os.WriteFile(filepath.Join(procDir, "cgroup"), []byte(cgroupContent), 0o644))
	}

	for _, pid := range nonContainerPIDs {
		procDir := filepath.Join(fakeProcfs, fmt.Sprintf("%d", pid))
		require.NoError(t, os.MkdirAll(procDir, 0o777))

		statusContent := fmt.Sprintf("Name:\ttest\nPid:\t%d\nPPid:\t1\nUid:\t0\t0\t0\t0\nGid:\t0\t0\t0\t0\nNStgid:\t%d\nNSpid:\t%d\nNSpgid:\t0\nNSsid:\t0\n", pid, pid, pid)
		require.NoError(t, os.WriteFile(filepath.Join(procDir, "status"), []byte(statusContent), 0o644))
		require.NoError(t, os.WriteFile(filepath.Join(procDir, "uid_map"), []byte("      0       0 4294967295\n"), 0o644))
		require.NoError(t, os.WriteFile(filepath.Join(procDir, "cgroup"), []byte("0::/\n"), 0o644))
	}

	return fakeProcfs
}
