	mockProbe := &MockSSLProbe{
		AttachCallCount: make(map[uint64]int),
		DetachCallCount: make(map[uint64]int),
	}

	monitor := NewContainerMonitor(mockProbe, "", "", nil)

	// Simulate the race: container is in activeContainers and both detach+attach
	// actions are queued, with detach arriving first.
	cgroupID := uint64(555)
	monitor.mu.Lock()
	monitor.activeContainers[cgroupID] = DetectedContainerInfo{
		CgroupID:    cgroupID,
		ContainerID: "deadbeef" + "deadbeef" + "deadbeef" + "deadbeef" + "deadbeef" + "deadbeef" + "deadbeef" + "deadbeef",
		HostPID:     1234,
	}
	monitor.mu.Unlock()

	// Queue detach first (as HandleCgroupRmdirEvent would), then attach (as scan would).
	// Also remove from activeContainers as HandleCgroupRmdirEvent does.
	monitor.mu.Lock()
	delete(monitor.activeContainers, cgroupID)
	monitor.mu.Unlock()

	monitor.actionCh <- containerAction{action: actionDetach, cgroupID: cgroupID}
	monitor.actionCh <- containerAction{action: actionAttach, cgroupID: cgroupID, hostPID: 1234}

	// Start the worker, let it drain both actions, then stop
	monitor.Start(context.Background())
	monitor.Stop()

	assert.Equal(t, 1, mockProbe.DetachCallCount[cgroupID], "DetachFromContainerLibs should be called once")
	assert.Equal(t, 0, mockProbe.AttachCallCount[cgroupID], "AttachToContainerLibs should NOT be called for removed container")
}
