	cm.mu.Lock()
	defer cm.mu.Unlock()

	if event.PID != 1 { // event.PID is NSPID
		return // Not an init process
	}

	cgroupPath, exists := cm.pendingCgroups[event.CgroupID]
	if !exists {
		if _, isAlreadyActive := cm.activeContainers[event.CgroupID]; isAlreadyActive {
			slog.Debug("ContainerMonitor: ExecveEvent for already known container",
				"cgroupID", event.CgroupID, "hostPID", event.HostPID)
		}
		return
	}

	delete(cm.pendingCgroups, event.CgroupID)

	containerID, err := procutils.ExtractContainerIDFromCgroupPath(cgroupPath)
	if err != nil {
		slog.Debug("ContainerMonitor: Failed to extract ContainerID from cgroup path, not treating as container init",
			"cgroupPath", cgroupPath, "cgroupID", event.CgroupID, "err", err)
		return
	}

	info := DetectedContainerInfo{
		CgroupID:    event.CgroupID,
		ContainerID: containerID,
		HostPID:     event.HostPID,
	}
	// Overwrite is acceptable here ??? if the scan already added this container,
	// AttachToContainerLibs has its own dedup via containerLinks.
	cm.activeContainers[event.CgroupID] = info

	slog.Info("ContainerMonitor: New container's init process detected!",
		"cgroupID", info.CgroupID,
		"containerID", info.ContainerID,
		"hostPID", info.HostPID,
		"exe", event.ExePath)

	cm.trySendAction(containerAction{action: actionAttach, cgroupID: info.CgroupID, hostPID: info.HostPID})
}
"},{"node":"scanExistingContainers","qualified_name":"Users-ilyabrykau-src-orca-runtime-sensor.pkg.containermonitor.monitor_unix.scanExistingContainers","label":"Method","file":"pkg/containermonitor/monitor_unix.go","start_line":38,"end_line":138,"in_degree":6,"out_degree":4,"match_lines":[38],"source":"func (cm *ContainerMonitor) scanExistingContainers(resolver cgroupIDResolver) {
	if !cm.initialScanCompleted.CompareAndSwap(false, true) {
		slog.Error("ContainerMonitor: initial scan already completed")
		return
	}

	fs, err := procfs.NewFS(cm.procfsDir)
	if err != nil {
		slog.Warn("ContainerMonitor: failed to open procfs, skipping existing container scan",
			slog.Any("err", err))
		return
	}

	procs, err := fs.AllProcs()
	if err != nil {
		slog.Warn("ContainerMonitor: failed to list processes, skipping existing container scan",
			slog.Any("err", err))
		return
	}

	slog.Debug("ContainerMonitor: initial scan starting",
		slog.Int("total_procs", len(procs)),
		slog.String("procfsDir", cm.procfsDir))

	attachedCount := 0
	nsPid1Count := 0
	errorCount := 0
	for _, proc := range procs {
		// Check if we're being shut down
		select {
		case <-cm.stopCh:
			slog.Info("ContainerMonitor: initial scan interrupted by shutdown")
			return
		default:
		}

		pid := uint32(proc.PID)

		// Check if this is a container init process (NsPid == 1)
		info, err := cm.procUtils.GetIdInformation(cm.procfsDir, pid)
		if err != nil {
			errorCount++
			slog.Debug("ContainerMonitor: skipping process during initial scan",
				slog.Any("pid", pid), slog.Any("err", err))
			continue
		}
		if info.NsPid != 1 {
			continue
		}
		nsPid1Count++

		// Extract container ID using the same parser as the event-driven path
		// (ExtractContainerIDFromCgroupPath requires a 64-char hex ID).
		containerID, err := extractContainerIDFromProc(cm.procfsDir, pid)
		if err != nil || containerID == "" {
			slog.Debug("ContainerMonitor: process has NsPid=1 but no container ID, skipping",
				slog.Any("pid", pid), slog.Any("err", err))
			continue
		}
		slog.Debug("ContainerMonitor: found container init process",
			slog.Any("pid", pid), slog.String("containerID", containerID))

		// Resolve the kernel cgroup ID
		cgroupID, err := resolver.ResolveCgroupID(cm.procfsDir, pid)
		if err != nil {
			slog.Debug("ContainerMonitor: failed to resolve cgroup ID for process",
				slog.Any("pid", pid), slog.Any("containerID", containerID), slog.Any("err", err))
			continue
		}

		// Register in activeContainers (under lock, check for duplicates)
		cm.mu.Lock()
		if _, exists := cm.activeContainers[cgroupID]; exists {
			cm.mu.Unlock()
			continue
		}
		cm.activeContainers[cgroupID] = DetectedContainerInfo{
			CgroupID:    cgroupID,
			ContainerID: containerID,
			HostPID:     pid,
		}
		cm.mu.Unlock()

		// Send attach action through actionCh so all AttachToContainerLibs calls
		// are serialized in the worker goroutine. This avoids a TOCTOU race in
		// ssl.go where concurrent callers can both pass the dedup check.
		select {
		case cm.actionCh <- containerAction{action: actionAttach, cgroupID: cgroupID, hostPID: pid}:
			attachedCount++
		case <-cm.stopCh:
			slog.Info("ContainerMonitor: initial scan interrupted by shutdown")
			return
		}
	}

	slog.Info("ContainerMonitor: initial scan of pre-existing containers complete",
		slog.Int("total_procs", len(procs)),
		slog.Int("nsPid1_found", nsPid1Count),
		slog.Int("errors", errorCount),
		slog.Int("containersAttached", attachedCount))
}
