"},{"node":"worker","qualified_name":"Users-ilyabrykau-src-orca-runtime-sensor.pkg.containermonitor.monitor.worker","label":"Method","file":"pkg/containermonitor/monitor.go","start_line":93,"end_line":135,"in_degree":2,"out_degree":5,"match_lines":[93],"source":"func (cm *ContainerMonitor) worker(ctx context.Context) {
	defer close(cm.done)

	// Scan for pre-existing containers concurrently so the worker immediately
	// starts draining actionCh. The scan sends attach actions through actionCh,
	// so all AttachToContainerLibs calls are serialized in this worker goroutine.
	// initExistingContainerScan is platform-specific (unix/windows).
	go func() {
		defer cm.scanWg.Done()
		cm.initExistingContainerScan()
	}()

	for action := range cm.actionCh {
		if cm.sslProbe == nil {
			continue
		}
		switch action.action {
		case actionAttach:
			if cm.Enabled != nil && !cm.Enabled() {
				slog.Debug("ContainerMonitor: skipping attach, feature disabled",
					"cgroupID", action.cgroupID)
				continue
			}
			cm.mu.Lock()
			_, stillActive := cm.activeContainers[action.cgroupID]
			cm.mu.Unlock()
			if !stillActive {
				slog.Debug("ContainerMonitor: skipping attach for removed container",
					"cgroupID", action.cgroupID)
				continue
			}
			if err := cm.sslProbe.AttachToContainerLibs(action.cgroupID, action.hostPID); err != nil {
				slog.Error("Failed to attach SSL probes to container",
					"cgroupID", action.cgroupID, "err", err)
			}
		case actionDetach:
			if err := cm.sslProbe.DetachFromContainerLibs(action.cgroupID); err != nil {
				slog.Error("ContainerMonitor: Error detaching SSL probes",
					"cgroupID", action.cgroupID, "err", err)
			}
		}
	}
}
