	silenceLogs(b)
	probe := &noopSSLProbe{}
	mon := NewContainerMonitor(probe, "", "", nil)

	// Pre-populate active containers so the worker doesn't skip them.
	for i := 0; i < b.N; i++ {
		cgroupID := uint64(i)
		mon.activeContainers[cgroupID] = DetectedContainerInfo{
			CgroupID: cgroupID,
			HostPID:  uint32(i + 1000),
		}
	}

	ctx, cancel := context.WithCancel(context.Background())

	// Fill the channel, then close it so the worker drains and exits.
	actions := make([]containerAction, b.N)
	for i := 0; i < b.N; i++ {
		actions[i] = containerAction{
			action:   actionAttach,
			cgroupID: uint64(i),
			hostPID:  uint32(i + 1000),
		}
	}

	b.ResetTimer()
	b.ReportAllocs()

	// Feed all actions, then close.
	go func() {
		for _, a := range actions {
			mon.actionCh <- a
		}
		close(mon.actionCh)
	}()

	// Run worker synchronously for measurement.
	mon.worker(ctx)
	cancel()
}
